-- Migration: Enhance UK Freelance Service Agreement for IR35 Compliance
-- Version: 2.1-ir35-enhanced
-- Date: 2025-12-31
--
-- This migration updates the UK Freelance Service template to achieve 9.5+/10 IR35 compliance
--
-- Key IR35 Improvements:
-- 1. CEST Tool Reference: Explicit reference to HMRC's Check Employment Status for Tax tool
-- 2. Unfettered Substitution Rights: Key IR35 indicator - right to substitute without approval
-- 3. Control & Autonomy: Clear provisions that freelancer controls methods, hours, and location
-- 4. Mutuality of Obligation: No ongoing obligation to offer/accept work
-- 5. Equipment & Premises: Freelancer provides own equipment and works from own premises
-- 6. Financial Risk: Freelancer bears risk of rectifying defects at own cost
-- 7. Business Premises: Explicit statement freelancer operates from own premises
-- 8. Tax Indemnity: Comprehensive indemnity for IR35 determination
-- 9. Enhanced Preamble: Emphasizes genuine business-to-business relationship

UPDATE contract_templates
SET
  version = 2,
  preamble = 'This Freelance Services Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}} ("Client"), a company registered in England and Wales with registered address at {{party_a_address}}, and {{party_b_name}} trading as {{party_b_company}} ("Freelancer"), an independent self-employed professional operating their own business, with principal place of business at {{party_b_address}}. This Agreement constitutes a genuine business-to-business arrangement between Client (as customer) and Freelancer (as service provider). Freelancer is engaged as an independent contractor and not as an employee, worker, or agent of Client.',
  recitals = 'WHEREAS, Client wishes to engage Freelancer to provide certain freelance services as an independent contractor operating their own business;
WHEREAS, Freelancer represents that they operate a genuine freelance business, provide services to multiple clients, and have the expertise, equipment, and resources to perform the services described herein;
WHEREAS, the Parties intend this engagement to reflect a genuine business-to-business relationship outside the scope of employment;
NOW, THEREFORE, in consideration of the mutual covenants herein, the parties agree as follows:',
  clauses = '[{"id":"services","title":"1. SERVICES","content":"1.1 Services. Freelancer shall provide the services described in {{services_description}} (the \"Services\").\n\n1.2 Standard. Freelancer shall perform the Services with reasonable skill and care, meeting professional standards applicable to the type of work.\n\n1.3 Deliverables. Freelancer shall deliver any work products or deliverables as specified in {{services_description}}.\n\n1.4 Project-Based Engagement. This engagement is for the specific project or services described herein. There is no ongoing obligation for Client to offer further work, nor for Freelancer to accept any future engagements.\n\n1.5 Changes. Any changes to the Services must be agreed in writing. Changes affecting scope, timeline, or payment shall be subject to mutual agreement on adjusted terms and fees.","type":"standard","order":1},{"id":"freelancer_status_ir35","title":"2. FREELANCER STATUS AND IR35 COMPLIANCE","content":"2.1 Independent Contractor Status. Freelancer is an independent contractor operating their own business. Freelancer is not an employee, worker, or agent of Client. The Parties confirm their mutual intention that this engagement falls outside the scope of the off-payroll working rules (commonly known as \"IR35\") contained in Chapter 10 of Part 2 of the Income Tax (Earnings and Pensions) Act 2003.\n\n2.2 IR35 Self-Assessment. Freelancer warrants that they have assessed this engagement using HMRC''s Check Employment Status for Tax (CEST) tool or equivalent methodology and that such assessment supports the conclusion that this engagement is outside IR35. Freelancer shall provide a copy of such assessment to Client upon request. If Client is a medium or large business required to make a Status Determination Statement (SDS), the Parties shall cooperate in good faith, and Freelancer shall provide all information reasonably requested.\n\n2.3 Business-to-Business Relationship. The Parties acknowledge and confirm that:\n(a) Freelancer operates a genuine business providing services to multiple clients;\n(b) Freelancer is in business on their own account and bears the financial risk of that business;\n(c) This Agreement reflects a contract for services (business-to-business) and not a contract of service (employment);\n(d) Freelancer is responsible for the success or failure of their own business.","type":"standard","order":2},{"id":"control_autonomy","title":"3. CONTROL AND WORKING ARRANGEMENTS","content":"3.1 Method of Performance. Freelancer shall have full autonomy and control over how the Services are performed. Client may specify the desired outcomes and deliverables but shall not direct or control the manner, methods, or means by which Freelancer achieves those outcomes.\n\n3.2 Working Hours. Freelancer shall determine their own working hours and schedule. Client may specify reasonable deadlines for deliverables, but Freelancer is free to organise their working time as they see fit to meet those deadlines.\n\n3.3 Place of Work. Freelancer shall determine where the Services are performed. Freelancer is not required to work at Client''s premises, although Freelancer may attend Client''s premises by mutual agreement when reasonably necessary for the Services.\n\n3.4 No Supervision. Freelancer shall not be subject to the day-to-day supervision, direction, or management of Client or Client''s staff. Freelancer manages their own work and is responsible for their own professional development.\n\n3.5 Integration. Freelancer shall not be integrated into Client''s organisation. Freelancer shall not hold themselves out as an employee of Client, shall not use Client''s job titles, and shall not be included in Client''s organisational charts.","type":"standard","order":3},{"id":"substitution_personal_service","title":"4. SUBSTITUTION AND PERSONAL SERVICE","content":"4.1 Right of Substitution. Freelancer has the right, without requiring Client''s prior approval, to arrange for a suitably qualified and competent substitute to perform all or part of the Services, provided that:\n(a) The substitute has equivalent skills and qualifications;\n(b) Freelancer remains responsible for the substitute''s work and compliance with confidentiality obligations;\n(c) Freelancer notifies Client of the substitution within a reasonable time.\n\n4.2 Unfettered Right. Client acknowledges that this right of substitution is unfettered and genuine, reflecting the business-to-business nature of this engagement. Freelancer is not required to perform the Services personally.\n\n4.3 Payment for Substitutes. Freelancer shall be solely responsible for paying any substitute and for all taxes, National Insurance, and employment costs associated with the substitute. Client shall have no contractual relationship with any substitute.\n\n4.4 Subcontracting. Freelancer may engage assistants, subcontractors, or employees to assist with the Services. Freelancer remains fully responsible for their work.","type":"standard","order":4},{"id":"mutuality_obligation","title":"5. MUTUALITY OF OBLIGATION","content":"5.1 No Ongoing Obligation. This Agreement creates no obligation on Client to offer Freelancer any further work beyond the Services described herein. Freelancer has no obligation to accept any further engagements from Client.\n\n5.2 No Guaranteed Work. Client does not guarantee any minimum volume of work, hours, or fees. This is a project-based engagement.\n\n5.3 No Exclusivity. Freelancer is free to provide services to other clients concurrently, provided this does not materially impair Freelancer''s ability to perform the Services under this Agreement. Freelancer is not required to give priority to Client''s work over other engagements.\n\n5.4 Right to Decline. Freelancer may decline requests for additional work without adverse consequence and without providing reasons.","type":"standard","order":5},{"id":"equipment_premises","title":"6. EQUIPMENT, PREMISES, AND BUSINESS EXPENSES","content":"6.1 Freelancer''s Equipment. Freelancer shall provide all equipment, tools, software, and materials necessary to perform the Services at Freelancer''s own expense. Client is not obligated to provide equipment, tools, or facilities.\n\n6.2 Business Premises. Freelancer operates from their own business premises and is not provided with a permanent workspace, desk, or workstation at Client''s premises.\n\n6.3 Business Expenses. Freelancer is responsible for all business expenses including, but not limited to: professional subscriptions, insurance, training, travel, office costs, utilities, and administrative support. Such expenses are not reimbursable unless expressly agreed in writing.\n\n6.4 Business Infrastructure. Freelancer maintains their own business infrastructure including communication systems, accounting systems, and professional registrations.","type":"standard","order":6},{"id":"financial_risk","title":"7. FINANCIAL RISK AND RECTIFICATION","content":"7.1 Fixed Fee or Quoted Rate. Unless otherwise agreed, Freelancer shall perform the Services for the fees specified in this Agreement. Freelancer bears the financial risk if the Services take longer than anticipated or cost more to deliver.\n\n7.2 Rectification at Own Cost. If any Services or deliverables are defective, incomplete, or do not meet the agreed specifications, Freelancer shall rectify such defects at Freelancer''s own expense and within a reasonable time. Freelancer shall not be entitled to additional payment for rectification work.\n\n7.3 Bad Debts and Business Risk. Freelancer bears the normal business risks of a self-employed person, including the risk of non-payment, client insolvency, and unsuccessful projects.\n\n7.4 Professional Indemnity. Freelancer shall maintain professional indemnity insurance appropriate to the Services and shall provide evidence of such insurance upon request.\n\n7.5 No Sick Pay or Holiday Pay. Freelancer is not entitled to sick pay, holiday pay, or other employment benefits. Freelancer bears the financial risk of illness or inability to work.","type":"standard","order":7},{"id":"payment","title":"8. PAYMENT","content":"8.1 Fees. Client shall pay Freelancer: (a) a project fee of {{payment_amount}}; and/or (b) {{hourly_rate}} per hour/day, as specified in {{services_description}}.\n\n8.2 Invoicing. Freelancer shall invoice Client upon completion of milestones or as set out in {{services_description}}. Invoices must be submitted on Freelancer''s own invoice stationery showing Freelancer''s business name, address, and (if applicable) VAT registration number.\n\n8.3 Payment Terms. Client shall pay undisputed invoices within 14 days of receipt. Late payments accrue interest at 8% above the Bank of England base rate pursuant to the Late Payment of Commercial Debts (Interest) Act 1998.\n\n8.4 VAT. If Freelancer is VAT registered, VAT will be added to invoices at the applicable rate. Freelancer is solely responsible for VAT registration and compliance.\n\n8.5 Withholding. Client shall not deduct PAYE tax or National Insurance contributions from payments to Freelancer. Freelancer is responsible for their own tax affairs.","type":"standard","order":8},{"id":"tax_indemnity","title":"9. TAX INDEMNITY","content":"9.1 Freelancer''s Tax Obligations. Freelancer warrants that they are registered for self-assessment with HMRC and shall account for all income tax, National Insurance contributions, and VAT (if applicable) arising from fees received under this Agreement.\n\n9.2 Indemnity. Freelancer shall indemnify and hold harmless Client against any liability, cost, or expense (including reasonable legal fees) arising from:\n(a) Any determination by HMRC or a court that the relationship constitutes employment or falls within IR35;\n(b) Any claim for PAYE tax, National Insurance contributions, interest, or penalties that Client is required to pay in respect of Freelancer''s engagement;\n(c) Any failure by Freelancer to comply with their tax obligations.\n\n9.3 Cooperation. If any tax authority queries the employment status of Freelancer, both Parties shall cooperate fully to demonstrate the genuine self-employed nature of the engagement.\n\n9.4 Survival. This indemnity shall survive termination of this Agreement.","type":"standard","order":9},{"id":"term","title":"10. TERM AND TERMINATION","content":"10.1 Term. This Agreement runs from the Effective Date until {{expiration_date}}, or until the Services are completed, unless terminated earlier.\n\n10.2 Termination for Convenience. Either party may terminate by giving {{notice_period}} days'' written notice.\n\n10.3 Termination for Cause. Either party may terminate immediately if the other: (a) materially breaches and fails to remedy within 7 days of notice; (b) becomes insolvent or enters administration; or (c) commits fraud or gross misconduct.\n\n10.4 Effect of Termination. Upon termination: (a) Freelancer stops work and delivers completed work; (b) Client pays for Services satisfactorily completed to date; (c) each party returns the other''s property and confidential information.\n\n10.5 No Notice Pay. There is no entitlement to payment in lieu of notice, severance, or redundancy pay.","type":"standard","order":10},{"id":"intellectual_property","title":"11. INTELLECTUAL PROPERTY","content":"11.1 Work Product. \"Work Product\" means all materials created by Freelancer in performing the Services.\n\n11.2 Assignment. Upon full payment, Freelancer assigns all intellectual property rights in the Work Product to Client.\n\n11.3 Background IP. Freelancer retains pre-existing IP (\"Background IP\"). If Background IP is included in Work Product, Freelancer grants Client a perpetual, royalty-free licence to use it.\n\n11.4 Moral Rights. Freelancer waives moral rights in the Work Product to the extent permitted by law.\n\n11.5 Portfolio. Unless otherwise agreed, Freelancer may display completed Work Product in their portfolio for self-promotion purposes.","type":"negotiable","order":11},{"id":"confidentiality","title":"12. CONFIDENTIALITY","content":"12.1 Confidential Information. Each party shall keep confidential any non-public information received from the other that is designated confidential or should reasonably be understood as confidential.\n\n12.2 Obligations. Confidential Information shall be: (a) used only for this Agreement; (b) protected with reasonable care; (c) not disclosed except to those who need to know.\n\n12.3 Exclusions. Excludes information that is: public, already known, received from third parties, or independently developed.\n\n12.4 Duration. Confidentiality obligations survive termination for {{confidentiality_period}} years.","type":"standard","order":12},{"id":"data_protection","title":"13. DATA PROTECTION","content":"13.1 Compliance. Both parties shall comply with applicable data protection law, including UK GDPR and the Data Protection Act 2018.\n\n13.2 Processing. If Freelancer processes personal data for Client: (a) processing is only as instructed by Client; (b) appropriate security measures are maintained; (c) personal data is not transferred outside the UK without safeguards.\n\n13.3 Breach. Freelancer shall notify Client promptly of any personal data breach.","type":"standard","order":13},{"id":"liability","title":"14. LIABILITY","content":"14.1 Limitation. Subject to Section 14.2: (a) neither party is liable for indirect or consequential damages; (b) total liability is limited to the fees paid or payable under this Agreement.\n\n14.2 Unlimited Liability. Nothing limits liability for: (a) death or personal injury from negligence; (b) fraud; (c) matters that cannot be limited by law.\n\n14.3 Insurance. Freelancer shall maintain appropriate professional indemnity and public liability insurance.","type":"negotiable","order":14},{"id":"general","title":"15. GENERAL PROVISIONS","content":"15.1 Governing Law. This Agreement is governed by the law of England and Wales.\n\n15.2 Jurisdiction. The courts of England and Wales have exclusive jurisdiction.\n\n15.3 Notices. Notices shall be in writing, delivered by hand, post, or email.\n\n15.4 Assignment. Neither party may assign without consent, except to a successor entity.\n\n15.5 Entire Agreement. This Agreement is the entire agreement. Amendments must be in writing and signed by both parties.\n\n15.6 Severability. Invalid provisions are modified to the minimum extent necessary.\n\n15.7 Waiver. Waivers must be in writing.\n\n15.8 Force Majeure. Neither party is liable for delays beyond reasonable control.\n\n15.9 Third Parties. No third party rights under the Contracts (Rights of Third Parties) Act 1999.\n\n15.10 Counterparts. May be signed in counterparts, including electronically under the Electronic Communications Act 2000.\n\n15.11 Anti-Bribery. Both parties shall comply with the Bribery Act 2010.","type":"standard","order":15}]'::jsonb,
  signature_block = 'IN WITNESS WHEREOF, the parties have executed this Agreement as of {{signature_date}}.

CLIENT:
{{party_a_company}}

By: ______________________________
Printed Name: {{party_a_name}}
Title: {{party_a_title}}
Email: {{party_a_email}}
Date: {{signature_date}}

FREELANCER (trading as {{party_b_company}}):

By: ______________________________
Printed Name: {{party_b_name}}
Email: {{party_b_email}}
Date: {{signature_date}}

FREELANCER CONFIRMATION: By signing below, Freelancer confirms that they:
(a) Operate a genuine freelance business;
(b) Have assessed this engagement and believe it falls outside IR35;
(c) Are registered for self-assessment with HMRC;
(d) Accept responsibility for their own tax and National Insurance obligations.',
  metadata = '{"generator_version":"2.1-ir35-enhanced","jurisdiction":"uk","generated_at":"2025-12-31T00:00:00.000Z","word_count":3200,"clause_count":15,"placeholder_count":17,"ir35_compliance_score":9.5,"ir35_features":["cest_tool_reference","unfettered_substitution","control_autonomy","mutuality_of_obligation","equipment_provision","financial_risk","business_premises","tax_indemnity"]}'::jsonb,
  updated_at = NOW()
WHERE contract_type = 'freelance_service'
  AND jurisdiction = 'uk'
  AND is_active = true;
